{{ 
(() => {
  const userId = $('DisparoInicial').item.json.body.userId.replace(/-/g, '_');
  const table = `empresa_${userId}`;
  const match = `matchNKW_documents_${table}`;

  return `
create table if not exists "${table}" (
  id bigserial primary key,
  content text,
  metadata jsonb,
  embedding vector(1536)
);

create or replace function "${match}" (
  query_embedding vector(1536),
  match_count int default null,
  filter jsonb default '{}'
) returns table (
  id bigint,
  content text,
  metadata jsonb,
  similarity float
)
as $fn$
#variable_conflict use_column
begin
  return query
  select
    id,
    content,
    metadata,
    1 - ("${table}".embedding <=> query_embedding) as similarity
  from "${table}"
  where metadata @> filter
  order by "${table}".embedding <=> query_embedding
  limit match_count;
end;
$fn$
language plpgsql;
`;
})()
}}

