const item = items[0];
const fullResponse = $('AgenteCoordenador1').first().json.output;

const sentences = fullResponse.split(/(?<=[.?!])\s+|\n\s*\n|\n(?=[A-Z])/)
                              .filter(s => s.trim() !== '');

if (sentences.length === 0 && fullResponse.trim() !== '') {
  sentences.push(fullResponse.trim());
}

// CRUCIAL: Criamos um array de OBJETOS, onde cada um tem uma chave "text".
item.json.messagesToSend = sentences.map(sentence => ({ text: sentence.trim() }));

// Retorna o item único com o array dentro.
return [item];

// Pega todos os itens da entrada como um array
const allItems = $input.all();

// --- Objetivo 1: Concatenar APENAS textos de 'text/plain' ---

// 1. Filtra os itens para pegar só os que são 'text/plain'
// 2. Mapeia para extrair o 'pageContent' APENAS desses itens filtrados
const allPlainTexts = allItems
  .filter(item => item.json.metadata.blobType === 'text/plain')
  .map(item => item.json.pageContent);

// 3. Junta todos os textos planos com uma nova linha
const textoCompleto = allPlainTexts.join('\n');

// --- Objetivo 2: Verificar se há documentos (PDF ou XLS/XLSX) ---

// 4. Define os "MIME types" que consideramos como documentos
const tiposDeDocumento = [
  'application/pdf',
  'application/vnd.ms-excel', // .xls
  'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' // .xlsx
];

// 5. Usa .some() no array ORIGINAL (allItems) para checar se 
//    *pelo menos um* item é um tipo de documento.
const contemDocumento = allItems.some(item => 
  tiposDeDocumento.includes(item.json.metadata.blobType)
);

const idAssinante = $('DadosUteis').first().json.IdAssinante

const numeroAssinante = $('DadosUteis').first().json.NumeroAssinante

// 6. Retorna ambos os resultados
return {
  textoConcatenado: textoCompleto,
  temDocumento: contemDocumento,
  idAssinante,
  numeroAssinante
};

